func (c *current) onDang6(e any) (any, error) {
	return e, nil
}

func (p *parser) callonDang6() (any, error) {
	stack := p.vstack[len(p.vstack)-1]
	_ = stack
	return p.cur.onDang6(stack["e"])
}

func (c *current) onDang1(eles, last any) (any, error) {
	return &FileBlock{
		Forms: sliceOfAppend[Node](eles, last),
		Loc:   c.Loc(),
	}, nil
}

func (p *parser) callonDang1() (any, error) {
	stack := p.vstack[len(p.vstack)-1]
	_ = stack
	return p.cur.onDang1(stack["eles"], stack["last"])
}

func (c *current) onDecl1(docstring, decl any) (any, error) {
	switch node := decl.(type) {
	case *InterfaceDecl:
		if docstring != nil {
			node.DocString = docstring.(string)
		}
		return node, nil
	case *UnionDecl:
		if docstring != nil {
			node.DocString = docstring.(string)
		}
		return node, nil
	case *EnumDecl:
		if docstring != nil {
			node.DocString = docstring.(string)
		}
		return node, nil
	case *ScalarDecl:
		if docstring != nil {
			node.DocString = docstring.(string)
		}
		return node, nil
	case *ObjectDecl:
		if docstring != nil {
			node.DocString = docstring.(string)
		}
		return node, nil
	case *FieldDecl:
		if docstring != nil {
			node.DocString = docstring.(string)
		}
		return node, nil
	case *DirectiveDecl:
		if docstring != nil {
			node.DocString = docstring.(string)
		}
		return node, nil
	case *NewConstructorDecl:
		if docstring != nil {
			node.DocString = docstring.(string)
		}
		return node, nil
	case *SelfBlockDecl:
		// A self { } block carries no docstring of its own; its members do.
		return node, nil
	default:
		return decl, nil
	}
}

func (p *parser) callonDecl1() (any, error) {
	stack := p.vstack[len(p.vstack)-1]
	_ = stack
	return p.cur.onDecl1(stack["docstring"], stack["decl"])
}

